#include <iostream>
int square(int x) {
    return x * x;
}
int main() {
    int result = square(5);
    std::cout << result;
}

#include <iostream>
int getMax(int a, int b) {
    if (a > b) return a;
    return b;
}
int main() {
    std::cout << getMax(3, 7) << " " << getMax(9, 2);
}

#include <iostream>
bool isEven(int n) {
    return n % 2 == 0;
}
int main() {
    std::cout << isEven(4) << " " << isEven(7);
}
